body.script:
(function () {
  function onReady() {
    if (performance && performance.measure) {
      try {
        performance.measure('scripts-deferred', 'scripts-deferred-start');
      } catch (e) {}
    }
    if (!window.__SCRIPTS_LOADED__['main']) {
      var failureEl = document.getElementById('ScriptLoadFailure');
      if (failureEl) failureEl.style.display = 'block';
      var criticalScripts = ["vendor","main"];
      for (var i = 0; i < criticalScripts.length; i++) {
        var criticalScript = criticalScripts[i];
        if (!window.__SCRIPTS_LOADED__[criticalScript]) {
          var failedInputs = document.getElementsByName('failedScript');
          if (failedInputs[0]) failedInputs[0].value = criticalScript;
          break;
        }
      }
    }
  }
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', onReady);
  } else {
    onReady();
  }
})();
